final:
module lfsr (
    input clk,
    input rst_n,
    output reg [9:0] lfsr_out
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
    if (!rst_n)
        lfsr_out <= 10'b1111111111;
    else begin
        lfsr_out <= {lfsr_out[8:0], lfsr_out[9] ^ lfsr_out[8]};
    end
end

endmodule
